import{_ as a,o,c,a3 as r}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module generate:cache","description":"The generate:cache module provides a caching layer for LLM promptтАУresponse pairs. It is responsible for constructing deterministic cache keys from normalized prompt and response text, storing entries in JSONL files alongside an inтАСmemory index, and performing both synchronous and asynchronous lookups and saves. The public interface includes functions such as make_prompt_response_cache_key, normalize_text_for_hashing, save_cache_entry, save_cache_entry_async, load_cache_index, load_cache_index_async, and find_cached_response, together with the CacheIndex and CacheError types that clients use to interact with the cache.","frontmatter":{"title":"Module generate:cache","description":"The generate:cache module provides a caching layer for LLM promptтАУresponse pairs. It is responsible for constructing deterministic cache keys from normalized prompt and response text, storing entries in JSONL files alongside an inтАСmemory index, and performing both synchronous and asynchronous lookups and saves. The public interface includes functions such as make_prompt_response_cache_key, normalize_text_for_hashing, save_cache_entry, save_cache_entry_async, load_cache_index, load_cache_index_async, and find_cached_response, together with the CacheIndex and CacheError types that clients use to interact with the cache.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/generate/cache.md","filePath":"en/clore/modules/generate/cache.md"}'),t={name:"clore/modules/generate/cache.md"};function i(n,e,s,d,l,h){return o(),c("div",null,[...e[0]||(e[0]=[r('<h1 id="module-generate-cache" tabindex="-1">Module <code>generate:cache</code> <a class="header-anchor" href="#module-generate-cache" aria-label="Permalink to &quot;Module `generate:cache`&quot;">тАЛ</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">тАЛ</a></h2><p>The <code>generate:cache</code> module provides a caching layer for LLM promptтАУresponse pairs. It is responsible for constructing deterministic cache keys from normalized prompt and response text, storing entries in JSONL files alongside an inтАСmemory index, and performing both synchronous and asynchronous lookups and saves. The public interface includes functions such as <code>make_prompt_response_cache_key</code>, <code>normalize_text_for_hashing</code>, <code>save_cache_entry</code>, <code>save_cache_entry_async</code>, <code>load_cache_index</code>, <code>load_cache_index_async</code>, and <code>find_cached_response</code>, together with the <code>CacheIndex</code> and <code>CacheError</code> types that clients use to interact with the cache.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">тАЛ</a></h2><ul><li><a href="./../protocol/"><code>protocol</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">тАЛ</a></h2><ul><li><a href="./scheduler"><code>generate:scheduler</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">тАЛ</a></h2><h3 id="clore-generate-cache-cacheerror" tabindex="-1"><code>clore::generate::cache::CacheError</code> <a class="header-anchor" href="#clore-generate-cache-cacheerror" aria-label="Permalink to &quot;`clore::generate::cache::CacheError`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:16</code></p><p>Definition: <code>generate/cache.cppm:16</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The struct <code>clore::generate::cache::CacheError</code> is a lightweight error type that stores a descriptive <code>std::string</code> in its only data member <code>message</code>. Internally, it relies solely on the invariants of <code>std::string</code>тАФthe string can be empty (indicating no detail) or contain an error explanation. No additional constructors, assignment <code>operator</code>s, or member functions are defined beyond the implicitly generated ones, making <code>CacheError</code> a trivially copyable and movable aggregate. Its design serves as a minimal, self-contained error representation for cache operations, providing a single point of failure information without any internal state management or resource ownership beyond the string itself.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">тАЛ</a></h4><ul><li><code>message</code> is a valid <code>std::string</code> (may be empty if no error details are provided)</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">тАЛ</a></h4><ul><li><code>message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>Returned or thrown to indicate cache operation failures</li><li>Inspected by callers to retrieve error details</li></ul><h3 id="clore-generate-cache-cacheindex" tabindex="-1"><code>clore::generate::cache::CacheIndex</code> <a class="header-anchor" href="#clore-generate-cache-cacheindex" aria-label="Permalink to &quot;`clore::generate::cache::CacheIndex`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:20</code></p><p>Definition: <code>generate/cache.cppm:20</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The struct <code>clore::generate::cache::CacheIndex</code> is a thin wrapper around a single data member: a <code>std::unordered_map&lt;std::string, std::string&gt;</code> named <code>entries</code>. Its role is to serve as a simple, standalone index mapping string keys to string values. Because the struct contains no additional logic or constraints, the only invariants are those inherited from the underlying unordered mapтАФnamely, that keys are unique (per the mapтАЩs semantics) and that both keys and values are valid <code>std::string</code> objects. No special member functions are defined, so the compiler-generated default constructor, copy/move operations, and destructor apply, preserving the mapтАЩs usual behavior. This minimal internal structure makes <code>CacheIndex</code> a straightforward value type whose entire state resides in the <code>entries</code> map.</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">тАЛ</a></h4><ul><li>The map is unordered; iteration order is unspecified.</li><li>Keys and values are strings.</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">тАЛ</a></h4><ul><li><code>entries</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>Used as a lightweight index for caching or lookup purposes.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">тАЛ</a></h2><h3 id="clore-generate-cache-find-cached-response" tabindex="-1"><code>clore::generate::cache::find_cached_response</code> <a class="header-anchor" href="#clore-generate-cache-find-cached-response" aria-label="Permalink to &quot;`clore::generate::cache::find_cached_response`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:35</code></p><p>Definition: <code>generate/cache.cppm:347</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The function performs a synchronous lookup of a cached response by converting the provided <code>cache_key</code> to a <code>std::string</code> and searching the <code>index.entries</code> map (an associative container, likely <code>std::unordered_map</code>). If the key is found, the associated value is returned as an <code>std::optional&lt;std::string_view&gt;</code>, otherwise <code>std::nullopt</code> is returned. The algorithm is a straightforward map lookup with no file I/O or external dependencies beyond the <code>CacheIndex</code> structure, making it a lightweight query that relies on the index having been previously loaded.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">тАЛ</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">тАЛ</a></h4><ul><li><code>index.entries</code> (the cache index map)</li><li><code>cache_key</code> (the lookup key)</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>Check existence of cached response before generation</li><li>Retrieve cached response by key from index</li></ul><h3 id="clore-generate-cache-load-cache-index" tabindex="-1"><code>clore::generate::cache::load_cache_index</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:29</code></p><p>Definition: <code>generate/cache.cppm:252</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The function <code>clore::generate::cache::load_cache_index</code> implements a cache index loader that reconstructs the inтАСmemory <code>CacheIndex</code> from persisted JSONL files. It first delegates to the helper <code>all_jsonl_files</code> to enumerate all JSONL files in the given <code>workspace_root</code>. If that enumeration fails, the error is propagated immediately via <code>std::unexpected</code>. For each file path returned, it reads the entire file content using <code>clore::support::read_utf8_text_file</code>; if reading fails for any file, that file is silently skipped.</p><p>The actual index construction iterates line by line through the file content using a <code>std::istringstream</code>. Empty lines are ignored. Each nonтАСempty line is parsed as a JSON object via <code>kota::codec::json::parse</code>. If parsing fails, the line is skipped. For a successful parse, the function extracts the <code>&quot;key&quot;</code> and <code>&quot;resp&quot;</code> fields as strings. If either field is missing or has an empty key, the line is silently ignored. Otherwise, it inserts a mapping from the key string to the response string into <code>index.entries</code> using <code>insert_or_assign</code>. This process repeats for all files, accumulating all cache entries. The final populated <code>CacheIndex</code> is returned on success. The function depends on <code>all_jsonl_files</code> for file discovery, <code>clore::support::read_utf8_text_file</code> for file I/O, <code>kota::codec::json::parse</code> for JSON deserialization, and the <code>CacheIndex</code> aggregate type.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">тАЛ</a></h4><ul><li>reads files from the file system</li><li>allocates memory for cache entries</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">тАЛ</a></h4><ul><li><code>workspace_root</code> parameter</li><li>JSONL files on disk</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>called to load cache index from disk</li><li>used at initialization to populate in-memory cache index</li></ul><h3 id="clore-generate-cache-load-cache-index-async" tabindex="-1"><code>clore::generate::cache::load_cache_index_async</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index-async" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index_async`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:38</code></p><p>Definition: <code>generate/cache.cppm:356</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The function <code>clore::generate::cache::load_cache_index_async</code> implements an asynchronous coroutine that wraps the synchronous <code>load_cache_index</code> by offloading its execution to a background thread via <code>kota::queue</code>. It accepts a <code>workspace_root</code> string and a <code>kota::event_loop</code> reference. Inside the coroutine, a lambda captures <code>workspace_root</code> by move and calls <code>load_cache_index</code> on it; the lambda is then queued on the provided <code>loop</code>. The resulting <code>kota::task</code> is <code>co_awaited</code>, and the returned <code>queued_result</code> is inspected for errors at two levels. If the queue task itself failed (for example due to cancellation), a new <code>CacheError</code> is produced with a descriptive message. Otherwise, if the inner <code>std::expected</code> contains an error, that error is forwarded via <code>kota::fail</code>. On success, the contained <code>CacheIndex</code> value is moved out with <code>co_return</code>. This design ensures that the blocking fileтАСsystem work of <code>load_cache_index</code> does not stall the event loop, while error propagation remains uniform through <code>CacheError</code>.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">тАЛ</a></h4><ul><li>reads cache index file from disk</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">тАЛ</a></h4><ul><li><code>workspace_root</code> parameter</li><li>filesystem cache index file</li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>asynchronous loading of cache index</li><li>wrapping synchronous <code>load_cache_index</code> into a coroutine</li></ul><h3 id="clore-generate-cache-make-prompt-response-cache-key" tabindex="-1"><code>clore::generate::cache::make_prompt_response_cache_key</code> <a class="header-anchor" href="#clore-generate-cache-make-prompt-response-cache-key" aria-label="Permalink to &quot;`clore::generate::cache::make_prompt_response_cache_key`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:24</code></p><p>Definition: <code>generate/cache.cppm:219</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The function computes a deterministic cache key by concatenating the <code>request_key</code> with hashed and fingerprinted representations of the requestтАЩs semantic components. It first obtains a fingerprint for the response format via <code>response_format_fingerprint</code>, immediately propagating any error as an unexpected <code>CacheError</code>. The prompt and system prompt are normalized using <code>normalize_text_for_hashing</code> and then hashed with <code>llvm::xxh3_64bits</code> to produce fixed-size digests. A separate <code>tool_choice_fingerprint</code> is computed for the toolтАСchoice field. The final key is assembled by appending each hash and fingerprint, separated by tab characters, along with a singleтАСcharacter encoding of the <code>output_contract</code> flag. The key is built in a preтАСreserved string to minimize reallocations. This design ensures that structurally equivalent requests (after normalization) always map to the same cache key, while variations in any tracked property produce distinct keys.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">тАЛ</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">тАЛ</a></h4><ul><li><code>request_key</code></li><li><code>system_prompt</code></li><li><code>request.prompt</code></li><li><code>request.response_format</code></li><li><code>request.tool_choice</code></li><li><code>request.output_contract</code></li><li><code>normalize_text_for_hashing</code></li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>Used by <code>find_cached_response</code> and <code>save_cache_entry</code> to generate a unique key for cache operations.</li></ul><h3 id="clore-generate-cache-normalize-text-for-hashing" tabindex="-1"><code>clore::generate::cache::normalize_text_for_hashing</code> <a class="header-anchor" href="#clore-generate-cache-normalize-text-for-hashing" aria-label="Permalink to &quot;`clore::generate::cache::normalize_text_for_hashing`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:192</code></p><p>Definition: <code>generate/cache.cppm:192</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>Implementation: <a href="./functions/normalize-text-for-hashing">Implementation</a></p><p>The function first trims leading whitespace by advancing a <code>start</code> index past any characters for which <code>std::isspace</code> returns true. It then iterates over the remaining characters from <code>start</code> to the end of the input, using a <code>prev_space</code> flag to track whether the previous character was whitespace. When a nonтАСspace character is encountered, if <code>prev_space</code> is true and the result string is not empty, a single space character is appended before the character; otherwise only the character is appended. This collapses any run of internal whitespace into exactly one space. The result is a <code>std::string</code> with leading whitespace removed and interior whitespace sequences normalized to single spaces. The implementation avoids allocating extra memory by calling <code>reserve</code> on the result with the original input size, and relies solely on the standard library (<code>std::isspace</code>, <code>std::string</code>, <code>std::size_t</code>).</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">тАЛ</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">тАЛ</a></h4><ul><li>parameter <code>text</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">тАЛ</a></h4><ul><li>local variable <code>result</code> (returned by value)</li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>called by <code>make_prompt_response_cache_key</code> to normalize prompt and response text before deriving a cache key</li></ul><h3 id="clore-generate-cache-save-cache-entry" tabindex="-1"><code>clore::generate::cache::save_cache_entry</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:31</code></p><p>Definition: <code>generate/cache.cppm:303</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The function serialises the write operation by first acquiring a static <code>std::mutex</code> (<code>cache_file_mutex</code>) via a <code>std::lock_guard</code>. It then retrieves the cache directory path by calling <code>cache_directory(workspace_root)</code>; on failure, the error is forwarded. The directory is created with <code>fs::create_directories</code>, and any failure produces a <code>CacheError</code> with a descriptive message. Next, the target JSONL file path is formed by appending <code>current_jsonl_filename()</code> to the directory. The entry line is built by <code>build_jsonl_line(cache_key, response)</code>, which formats the keyтАСvalue pair as a JSON object. The file is opened in binary append mode (<code>std::ofstream</code> with <code>std::ios::binary | std::ios::app</code>). The line is written via <code>file.write</code> and immediately flushed; if the write operation fails, a <code>CacheError</code> is returned. On success, an empty <code>std::expected&lt;void, CacheError&gt;</code> is returned.</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">тАЛ</a></h4><ul><li>acquires a static mutex for synchronization</li><li>creates directories on the filesystem if they do not exist</li><li>opens a JSONL file for append binary writing</li><li>writes a line to the file and flushes the stream</li><li>may return observable error states in the result</li></ul><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">тАЛ</a></h4><ul><li>parameter <code>workspace_root</code></li><li>parameter <code>cache_key</code></li><li>parameter <code>response</code></li><li>result of <code>cache_directory</code></li><li>result of <code>current_jsonl_filename</code></li><li>result of <code>build_jsonl_line</code></li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">тАЛ</a></h4><ul><li>filesystem directories at path derived from <code>cache_directory</code></li><li>JSONL file at path combining <code>cache_directory</code> and <code>current_jsonl_filename</code></li><li>the return value (success or error state)</li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>called to persist a generated response to the cache</li><li>used after a successful generation to update the cache</li><li>likely invoked synchronously from a code path that just produced a response</li></ul><h3 id="clore-generate-cache-save-cache-entry-async" tabindex="-1"><code>clore::generate::cache::save_cache_entry_async</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry-async" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry_async`&quot;">тАЛ</a></h3><p>Declaration: <code>generate/cache.cppm:41</code></p><p>Definition: <code>generate/cache.cppm:376</code></p><p>Declaration: <a href="./../../namespaces/clore/generate/cache/"><code>Namespace clore::generate::cache</code></a></p><p>The function <code>clore::generate::cache::save_cache_entry_async</code> is an asynchronous wrapper that offloads the synchronous <code>clore::generate::cache::save_cache_entry</code> to a background task via <code>kota::queue</code>, using the provided <code>kota::event_loop</code> for scheduling. After capturing <code>workspace_root</code>, <code>cache_key</code>, and <code>response</code> by move, it <code>co_awaits</code> the queued lambda; if the task was cancelled, it fails with a <code>CacheError</code> with a descriptive message. If the queued operation itself produces an error (i.e., <code>save_cache_entry</code> returned <code>std::unexpected</code>), that error is forwarded by failing with the same <code>CacheError</code>. On success, the function <code>co_returns</code> without a value, effectively publishing the cache entry asynchronously. Its internal control flow depends entirely on the result of the synchronous <code>save_cache_entry</code> and the <code>kota</code> concurrency primitives (<code>kota::queue</code>, <code>kota::fail</code>, <code>kota::task</code>).</p><h4 id="side-effects-6" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-6" aria-label="Permalink to &quot;Side Effects&quot;">тАЛ</a></h4><ul><li>Writes a cache entry to persistent storage via <code>save_cache_entry</code></li></ul><h4 id="reads-from-6" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-6" aria-label="Permalink to &quot;Reads From&quot;">тАЛ</a></h4><ul><li><code>workspace_root</code> parameter</li><li><code>cache_key</code> parameter</li><li>response parameter</li><li>loop parameter</li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">тАЛ</a></h4><ul><li>Persistent cache storage (via <code>save_cache_entry</code>)</li></ul><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">тАЛ</a></h4><ul><li>Called to asynchronously persist a generated response to the cache</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">тАЛ</a></h2><p>The <code>generate:cache</code> module is decomposed into a public API and an internal helper layer. The public surface provides synchronous and asynchronous functions for loading cache indices (<code>load_cache_index</code>, <code>load_cache_index_async</code>), saving entries (<code>save_cache_entry</code>, <code>save_cache_entry_async</code>), and looking up cached responses (<code>find_cached_response</code>). Key construction is exposed via <code>make_prompt_response_cache_key</code>, which normalises prompt and response text before building a deterministic hash. Internally, the module relies on anonymousтАСnamespace helpers for fingerprinting <code>tool_choice</code> and <code>response_format</code>, enumerating JSONL files (<code>all_jsonl_files</code>), escaping JSON strings, and managing timestamped cache filenames.</p><p>The implementation imports <code>protocol</code> for LLMтАСrelated types, <code>support</code> for foundational utilities (UTFтАС8 I/O, path normalisation, hashing), and <code>std</code> for standard library facilities. Internal layering separates concerns: normalisation functions (<code>normalize_text_for_hashing</code>) feed into key generation, which is then used for index lookups and fileтАСbased storage. The cache stores entries in JSONL files within a directory derived from the workspace root; a <code>CacheIndex</code> structure holds inтАСmemory entries, and file access is serialised via mutexes. Asynchronous variants schedule work on a <code>kota::event_loop</code>, while synchronous paths perform blocking I/O. Error handling is unified through the <code>CacheError</code> type, returned via <code>std::expected</code>.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">тАЛ</a></h2><ul><li><a href="./../protocol/">Module protocol</a></li><li><a href="./../support/">Module support</a></li></ul>',121)])])}const f=a(t,[["render",i]]);export{u as __pageData,f as default};
